 1	import { FC, KeyboardEvent, MouseEvent, useEffect } from 'react';
 2	
 3	import { I18nNamespace } from '@config/config';
 4	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
 5	import { Tabs, Tab, TabTitleText } from '@patternfly/react-core';
 6	import { useTranslation } from 'react-i18next';
 7	
 8	const MenuTabsMapKey = {
 9	  getStarted: 0,
10	  details: 1,
11	  yaml: 2,
12	  links: 3,
13	  listeners: 4,
14	  connectors: 5
15	};
16	
17	interface TabNavigationProps {
18	  activeTabKey: string | number;
19	  setActiveTabKey: (tabIndex: string | number) => void;
20	}
21	
22	export const TabNavigation: FC<TabNavigationProps> = function ({ activeTabKey, setActiveTabKey }) {
23	  const { t } = useTranslation(I18nNamespace);
24	
25	  const { data: sites } = useWatchedSkupperResource({ kind: 'Site' });
26	  const site = sites?.[0];
27	
28	  const isConfigured = site?.isConfigured;
29	
30	  useEffect(() => {
31	    if (site?.hasError) {
32	      setActiveTabKey(1);
33	    }
34	  }, [setActiveTabKey, site?.hasError, site?.isConfigured]);
35	
36	  return (
37	    <Tabs
38	      mountOnEnter
39	      unmountOnExit
40	      activeKey={activeTabKey}
41	      onSelect={(_: MouseEvent | KeyboardEvent | MouseEvent, tabIndex: string | number) => setActiveTabKey(tabIndex)}
42	    >
43	      <Tab
44	        eventKey={MenuTabsMapKey.getStarted}
45	        title={<TabTitleText>{t('GetStartedTab')}</TabTitleText>}
46	        isDisabled={!isConfigured}
47	      />
48	      <Tab eventKey={MenuTabsMapKey.details} title={<TabTitleText>{t('DetailsTab')}</TabTitleText>} />
49	      <Tab eventKey={MenuTabsMapKey.yaml} title={<TabTitleText>{t('YamlTab')}</TabTitleText>} />
50	      <Tab
51	        eventKey={MenuTabsMapKey.links}
52	        title={<TabTitleText>{t('LinksTab')}</TabTitleText>}
53	        isDisabled={!isConfigured}
54	      />
55	      <Tab
56	        eventKey={MenuTabsMapKey.listeners}
57	        title={<TabTitleText>{t('ListenersTab')}</TabTitleText>}
58	        isDisabled={!isConfigured}
59	      />
60	      <Tab
61	        eventKey={MenuTabsMapKey.connectors}
62	        title={<TabTitleText>{t('ConnectorsTab')}</TabTitleText>}
63	        isDisabled={!isConfigured}
64	      />
65	    </Tabs>
66	  );
67	};

